response_text:
**Vulnerability:** OS Command Injection (CWE-78)
**Location:** `server.js`, line 7
**Explanation:** The code directly interpolates unsanitized user input (`req.query.domain`) into a shell command string using template literals and passes it to `child_process.exec()`. Because `exec()` invokes a system shell, an attacker can inject shell metacharacters via the query parameter (e.g., `?domain=example.com; cat /etc/passwd` or `?domain=$(id)`). The shell will interpret these as command separators or subshells, allowing arbitrary OS command execution with the privileges of the Node.js process.

**Fix:** Replace `exec()` with `execFile()` (or `spawn()`) to bypass the shell entirely, and add strict input validation to ensure only valid domain formats are accepted:
```javascript
const express = require("express");
const { execFile } = require("child_process"); // Use execFile instead of exec
const app = express();

app.get("/whois", (req, res) => {
    const domain = req.query.domain;

    // Strict validation: only allow alphanumeric characters, hyphens, and dots
    if (!domain || !/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/.test(domain)) {
        return res.status(400).send("Invalid domain format");
    }

    // execFile passes arguments directly to the binary without shell interpretation
    execFile("whois", [domain], (err, stdout) => {
        if (err) return res.status(500).send(err.message);
        res.type("text/plain").send(stdout);
    });
});
```

